def solve_662c240a(grid):
    rows = len(grid)
    block_size = rows // 3
    for i in range(3):
        block = [row[:] for row in grid[i*block_size:(i+1)*block_size]]
        is_symmetric = True
        for r in range(block_size):
            for c in range(block_size):
                if block[r][c] != block[c][r]:
                    is_symmetric = False
                    break
            if not is_symmetric:
                break
        if not is_symmetric:
            return block
